        int GetHealthTable(int qId, Dictionary<int, (string, string)> info)
        {
            if (!info.ContainsKey(qId)) return 30;
            var (enemyLevel, questLevel) = info[qId];
            return (enemyLevel, questLevel) switch
            {
                ("Village", "QL1") => 20,
                ("Village", "QL2") => 23,
                ("Village", "QL3") => 26,
                ("Village", "QL4") => 29,
                ("Village", "QL5") => 32,
                ("Village", "QL6") => 36,
                ("Low",     "QL1") => 64,
                ("Low",     "QL2") => 71,
                ("Low",     "QL3") => 85,
                ("High",    "QL1") => 95,
                ("High",    "QL4") => 97,
                ("High",    "QL5") => 99,
                ("High",    "QL6") => 101,
                ("High",    "QL7") => 103,
                ("High",    "QL7Ex") => 105,
                ("Master",  "QL1") => 115,
                ("Master",  "QL2") => 118,
                ("Master",  "QL3") => 121,
                ("Master",  "QL4") => 124,
                ("Master",  "QL5") => 128,
                ("Master",  "QL6") => 132,
                _ => 30
            };
        }

