        string[] allMonsterNames = monsterIdByName.Keys.ToArray();
        var options = new JsonSerializerOptions { WriteIndented = true };
        int created = 0, skipped = 0;

        // Lire tous les fichiers q*.json existants
        var sourceFiles = Directory.GetFiles("./quests", "q*.json");

        foreach (var sourceFile in sourceFiles)
        {
            string baseName = Path.GetFileName(sourceFile);
            if (!int.TryParse(baseName.Substring(1, baseName.Length - 6), out int questId))
                continue;

            string questJson = File.ReadAllText(sourceFile);
            JsonNode data = JsonNode.Parse(questJson)!;
            Random rng = new Random();

            // Le texte reste tel quel dans le fichier (pas de modification)

            if (huntingQuests.Contains(questId))
            {
                // Monstre cible random
                string targetName = allMonsterNames[rng.Next(allMonsterNames.Length)];
                int targetId = monsterIdByName[targetName];
                int targetIconId = monsterIconByName.ContainsKey(targetName) ? monsterIconByName[targetName] : 112;

                List<int> availableMaps = mapMonsters
                    .Where(kv => kv.Value.Contains(targetName))
                    .Select(kv => kv.Key)
                    .ToList();

                int chosenMap;
                List<string> companions;

                if (availableMaps.Count == 0)
                {
                    chosenMap = 10;
                    companions = new List<string>();
                }
                else
                {
                    chosenMap = availableMaps[rng.Next(availableMaps.Count)];
                    companions = mapMonsters[chosenMap].Where(m => m != targetName).ToList();
                }

                data["QuestData"]!["Monsters"]![0]!["Id"] = targetId;
                data["QuestData"]!["TargetMonsters"]![0] = targetId;
                data["QuestData"]!["Icons"]![0] = targetIconId;
                data["QuestData"]!["Map"] = chosenMap;

                for (int i = 1; i < 7; i++)
                {
                    if (companions.Count > 0)
                        data["QuestData"]!["Monsters"]![i]!["Id"] = monsterIdByName[companions[rng.Next(companions.Count)]];
                    else
                        data["QuestData"]!["Monsters"]![i]!["Id"] = 0;
                }

                if (chosenMap == 10)
                    data["EnemyData"]!["SmallMonsters"]!["SpawnType"] = 0;
                else
                    data["EnemyData"]!["SmallMonsters"]!["SpawnType"] = rng.Next(0, 51);

                // Conditions d'accès
                if (questConditions.ContainsKey(questId))
                {
                    var conds = questConditions[questId];
                    data["QuestData"]!["QuestConditions"]![0] = conds[0];
                    data["QuestData"]!["QuestConditions"]![1] = conds[1];
                }
            }

            // HealthTable et AttackTable selon la difficulté (s'applique à toutes les quêtes)
            int healthTable = GetHealthTable(questId, questInfo);
            int attackTable = GetAttackTable(questId, questInfo);
            for (int i = 0; i < 7; i++)
            {
                data["EnemyData"]!["Monsters"]![i]!["HealthTable"] = healthTable;
                data["EnemyData"]!["Monsters"]![i]!["AttackTable"] = attackTable;
            }
            data["EnemyData"]!["SmallMonsters"]!["HealthTable"] = healthTable;
            data["EnemyData"]!["SmallMonsters"]!["AttackTable"] = attackTable;

            // Appliquer les récompenses réelles
            if (questRewards.ContainsKey(questId))
            {
                var (zenny, vp, rp) = questRewards[questId];
                data["QuestData"]!["Reward"]!["Zenny"] = zenny;
                data["QuestData"]!["Reward"]!["Points"] = vp;
                data["QuestData"]!["Reward"]!["HRP"] = rp;
            }

            string fileName = Path.Combine(outputDir, $"q{questId}.json");
            File.WriteAllText(fileName, data.ToJsonString(options));
            created++;
        }

        Console.WriteLine($"{created} fichiers créés, {skipped} ignorés.");
